    [Fact]
    public void WFiltro_VistoHasValidValue_ShouldAddParameterAndWhereClause()
    {
        // Arrange
        var VistoValue = 1;
        var filtro = new FilterBensMateriais
        {
            Visto = VistoValue,
            LogicalOperator = " AND "
        };
        // Act
        var result = _serviceS.WFiltroBensMateriais(filtro);
        // Assert
        result.Should().NotBeNull();
        // Check parameter
        var VistoParameter = result.Value.parametros.FirstOrDefault(p => p.ParameterName == $"@{DBBensMateriaisDicInfo.Visto}");
        VistoParameter.Should().NotBeNull();
        VistoParameter.Value.Should().Be(VistoValue);
        // Check where clause
        result.Value.where.Should().Contain($"[{DBBensMateriaisDicInfo.PTabelaNome}].[{DBBensMateriaisDicInfo.Visto}] = @{DBBensMateriaisDicInfo.Visto}");
    }

